<script setup lang="ts">
import { Head, Link } from '@inertiajs/vue3';
import { ArrowLeft, BriefcaseBusiness, CalendarDays, CheckCircle2, FileCheck2, FolderOpen, MapPin, Send, Users } from '@lucide/vue';
import { computed, onMounted, ref } from 'vue';
import AppShell from '../../Layouts/AppShell.vue';

const props = defineProps<{ opportunityId: string }>();
const opportunity = ref<any>();
const library = ref<any[]>([]);
const selectedDocuments = ref<Record<string,string>>({});
const coverLetter = ref('');
const loading = ref(true);
const applying = ref(false);
const notice = ref('');
const error = ref('');
const csrf = () => document.querySelector<HTMLMetaElement>('meta[name="csrf-token"]')?.content ?? '';
const label = (value:string) => value.replaceAll('_',' ').replace(/\b\w/g, letter => letter.toUpperCase());
const location = computed(() => opportunity.value?.location?.is_remote ? 'Remote' : [opportunity.value?.location?.city, opportunity.value?.location?.province, opportunity.value?.location?.country].filter(Boolean).join(', '));
const daysLeft = computed(() => opportunity.value?.deadline ? Math.max(0, Math.ceil((+new Date(opportunity.value.deadline) - Date.now()) / 86400000)) : null);
const optionsFor = (requirement:any) => library.value.filter(media => media.collection === requirement.collection && media.processing_status === 'ready' && media.moderation_status === 'approved');
const missingRequired = computed(() => (opportunity.value?.required_documents ?? []).filter((requirement:any) => requirement.required && !selectedDocuments.value[requirement.key]));
const get = async (url:string) => { const response=await fetch(url,{credentials:'same-origin',headers:{Accept:'application/json'}});const payload=await response.json();if(!response.ok)throw new Error(payload.message);return payload.data??payload; };
const apply = async () => {
    applying.value=true;error.value='';notice.value='';
    try {
        if (missingRequired.value.length) throw new Error(`Select: ${missingRequired.value.map((item:any)=>item.label).join(', ')}.`);
        const documents=Object.entries(selectedDocuments.value).filter(([,mediaId])=>mediaId).map(([requirement_key,media_id])=>({requirement_key,media_id}));
        const response=await fetch(`/api/v1/opportunities/${props.opportunityId}/apply`,{method:'POST',credentials:'same-origin',headers:{Accept:'application/json','Content-Type':'application/json','X-CSRF-TOKEN':csrf()},body:JSON.stringify({cover_letter:coverLetter.value||null,documents})});
        const payload=await response.json();if(!response.ok)throw new Error(payload.message??Object.values(payload.errors??{}).flat().join(' '));
        opportunity.value.viewer.applied=true;notice.value='Application submitted successfully.';
    } catch (exception:any) { error.value=exception.message; } finally { applying.value=false; }
};
onMounted(async()=>{try{[opportunity.value,library.value]=await Promise.all([get(`/api/v1/opportunities/${props.opportunityId}`),get('/api/v1/media?per_page=50')]);}catch(exception:any){error.value=exception.message;}finally{loading.value=false;}});
</script>

<template><Head :title="opportunity?.title??'Opportunity'"/><AppShell><main class="opportunity-show"><Link class="opportunity-back" href="/opportunities"><ArrowLeft/>Back to opportunities</Link><div v-if="loading" class="opportunity-state">Loading opportunity…</div><div v-else-if="!opportunity" class="opportunity-state">{{error||'Opportunity unavailable.'}}</div><div v-else class="opportunity-layout"><article class="opportunity-detail"><header><span>{{label(opportunity.type)}}</span><h1>{{opportunity.title}}</h1><strong>{{opportunity.poster.name}}</strong></header><div class="opportunity-facts"><span><BriefcaseBusiness/>{{opportunity.sport?.name||'All sports'}}<template v-if="opportunity.position?.name"> · {{opportunity.position.name}}</template></span><span><MapPin/>{{location||'Location not specified'}}</span><span><CalendarDays/>{{daysLeft===null?'Open deadline':`${daysLeft} days left`}}</span><span><Users/>{{opportunity.applications_count}} applications</span></div><section><h2>About this opportunity</h2><p>{{opportunity.description}}</p></section><section><h2>Who they are looking for</h2><ul v-if="opportunity.requirements.length"><li v-for="requirement in opportunity.requirements" :key="requirement"><CheckCircle2/>{{requirement}}</li></ul><p v-else>No additional candidate requirements were specified.</p></section><section v-if="opportunity.required_documents.length"><h2>Documents requested</h2><div class="requested-documents"><span v-for="document in opportunity.required_documents" :key="document.key"><FileCheck2/><b>{{document.label}}</b><small>{{document.required?'Required':'Optional'}}</small></span></div></section></article><aside class="opportunity-apply"><template v-if="opportunity.viewer.applied"><CheckCircle2 class="applied-icon"/><h2>Application submitted</h2><p>You can track its progress from My applications.</p><Link href="/applications">View my applications</Link></template><template v-else><h2>Apply for this opportunity</h2><p>Select requested files already saved in your SportsUniverse Library.</p><form @submit.prevent="apply"><label v-for="document in opportunity.required_documents" :key="document.key"><span>{{document.label}} <b v-if="document.required">Required</b></span><select v-model="selectedDocuments[document.key]" :required="document.required"><option value="">Choose from Library</option><option v-for="media in optionsFor(document)" :key="media.id" :value="media.id">{{media.title||media.original_name}}</option></select><small v-if="!optionsFor(document).length">No matching files in your Library. <Link href="/profile/gallery">Add one</Link></small></label><label><span>Application message</span><textarea v-model="coverLetter" maxlength="5000" placeholder="Explain why you are a strong fit…"/></label><p v-if="error" class="application-error">{{error}}</p><p v-if="notice" class="application-success">{{notice}}</p><button :disabled="applying"><Send/>{{applying?'Submitting…':'Submit application'}}</button></form><Link class="library-link" href="/profile/gallery"><FolderOpen/>Manage my Library</Link></template></aside></div></main></AppShell></template>

<style scoped>
.opportunity-show{width:100%;max-width:1240px;margin:0 auto;padding:2rem 2rem 5rem}.opportunity-back{display:inline-flex;align-items:center;gap:.4rem;margin-bottom:1.2rem;color:#506078;font-size:.78rem;text-decoration:none}.opportunity-back svg{width:17px}.opportunity-layout{display:grid;grid-template-columns:minmax(0,1.6fr) minmax(320px,.7fr);gap:1.2rem}.opportunity-detail,.opportunity-apply{border:1px solid #dfe6ef;border-radius:18px;background:#fff}.opportunity-detail{padding:1.6rem}.opportunity-detail header>span{display:inline-flex;padding:.35rem .65rem;color:#476FEA;border-radius:999px;background:#eaf2ff;font-size:.68rem;font-weight:800}.opportunity-detail h1{margin:.75rem 0 .35rem;font-size:clamp(1.5rem,3vw,2.2rem)}.opportunity-detail header>strong{color:#526177}.opportunity-facts{display:grid;grid-template-columns:repeat(2,1fr);gap:.7rem;margin:1.5rem 0;padding:1rem;border-radius:13px;background:#f6f8fb}.opportunity-facts span{display:flex;align-items:center;gap:.4rem;color:#526177;font-size:.76rem}.opportunity-facts svg{width:16px;color:#476FEA}.opportunity-detail section{padding:1.2rem 0;border-top:1px solid #edf0f5}.opportunity-detail section h2{margin:0 0 .7rem;font-size:1rem}.opportunity-detail section p{color:#5f6d80;line-height:1.7;white-space:pre-line}.opportunity-detail ul{display:grid;gap:.65rem;padding:0;list-style:none}.opportunity-detail li{display:flex;gap:.5rem;align-items:flex-start;color:#4f5d70;font-size:.8rem}.opportunity-detail li svg{flex:none;width:17px;color:#19a66b}.requested-documents{display:grid;grid-template-columns:repeat(2,1fr);gap:.6rem}.requested-documents span{display:grid;grid-template-columns:auto 1fr;gap:.15rem .5rem;align-items:center;padding:.8rem;border:1px solid #e4e9f0;border-radius:11px}.requested-documents svg{grid-row:1/3;width:20px;color:#476FEA}.requested-documents b{font-size:.76rem}.requested-documents small{color:#7a8798;font-size:.62rem}.opportunity-apply{position:sticky;top:80px;align-self:start;padding:1.3rem}.opportunity-apply h2{margin:0 0 .35rem;font-size:1.1rem}.opportunity-apply>p{margin:0 0 1rem;color:#718096;font-size:.75rem;line-height:1.5}.opportunity-apply form{display:grid;gap:.9rem}.opportunity-apply label{display:grid;gap:.4rem}.opportunity-apply label>span{font-size:.72rem;font-weight:800}.opportunity-apply label b{color:#d92c5c;font-size:.58rem;text-transform:uppercase}.opportunity-apply select,.opportunity-apply textarea{width:100%;padding:.75rem;border:1px solid #dce3ed;border-radius:9px;background:#fff}.opportunity-apply textarea{min-height:130px;resize:vertical}.opportunity-apply label small{color:#8a95a5;font-size:.64rem}.opportunity-apply label small a{color:#476FEA}.opportunity-apply form>button,.opportunity-apply> a:not(.library-link){display:flex;justify-content:center;align-items:center;gap:.4rem;padding:.8rem;color:#fff;border:0;border-radius:10px;background:#476FEA;font-weight:800;text-decoration:none}.opportunity-apply form>button svg{width:17px}.library-link{display:flex;justify-content:center;gap:.35rem;align-items:center;margin-top:.8rem;color:#476FEA;font-size:.72rem;text-decoration:none}.library-link svg{width:16px}.application-error{margin:0;color:#c92850;font-size:.7rem}.application-success{margin:0;color:#168257;font-size:.7rem}.applied-icon{width:38px;height:38px;margin-bottom:.8rem;color:#19a66b}.opportunity-state{padding:4rem;text-align:center;color:#718096}
@media(max-width:800px){.opportunity-show{padding:1rem .85rem 4rem}.opportunity-layout{grid-template-columns:1fr}.opportunity-apply{position:static}.opportunity-facts,.requested-documents{grid-template-columns:1fr}.opportunity-detail{padding:1.1rem}}
</style>
